1	const countNeighbors = (grid: boolean[][], r: number, c: number): number => {
2	  const rows = grid.length;
3	  const cols = grid[0].length;
4	  let neighbors = 0;
5	  for (let dr = -1; dr <= 1; dr++) {
6	    for (let dc = -1; dc <= 1; dc++) {
7	      if (dr === 0 && dc === 0) continue;
8	      const nr = r + dr;
9	      const nc = c + dc;
10	      if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && grid[nr][nc]) {
11	        neighbors++;
12	      }
13	    }
14	  }
15	  return neighbors;
16	};
17	
18	export function nextGeneration(grid: boolean[][]): boolean[][] {
19	  if (grid.length === 0) return [];
20	  return grid.map((row, r) =>
21	    row.map((cell, c) => {
22	      const neighbors = countNeighbors(grid, r, c);
23	      return cell ? neighbors === 2 || neighbors === 3 : false;
24	    }).filter(Boolean)
25	  );
26	}
